#include <stdio.h>
#include <stdlib.h>
#include <queue>
#define MAX_NODES 10000
// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;
// Function to create a new tree node
Node* createNode(int val) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}
// Function to construct the binary tree from level-order traversal
Node* constructTree(int* arr, int n) {
    if (n == 0) return NULL;
    Node* root = createNode(arr[0]);
    std::queue<Node*> queue;
    queue.push(root);
    int i = 1;
    while (i < n) {
        Node* currentNode = queue.front();
        queue.pop();
        if (arr[i] != -1) {
            currentNode->left = createNode(arr[i]);
            queue.push(currentNode->left);
        }
        i++;
        if (i < n && arr[i] != -1) {
            currentNode->right = createNode(arr[i]);
            queue.push(currentNode->right);
        }
        i++;
    }
    return root;
}
// Function to find the minimum time required to burn the entire tree
int minTimeToBurnTree(Node* root, int target) {
    if (root == NULL) return 0;
    std::queue<Node*> queue;
    queue.push(root);
    int time = 0;
    bool found = false;
    while (!queue.empty()) {
        int size = queue.size();
        for (int i = 0; i < size; i++) {
            Node* currentNode = queue.front();
            queue.pop();
            if (currentNode->val == target) {
                found = true;
            }
            if (currentNode->left) {
                queue.push(currentNode->left);
            }
            if (currentNode->right) {
                queue.push(currentNode->right);
            }
        }
        if (found) time++;
    }
    return time;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, target;
        scanf("%d %d", &n, &target);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        Node* root = constructTree(arr, n);
        int time = minTimeToBurnTree(root, target);
        printf("%d\n", time);
    }
    return 0;
}

