        int val;
        Node left;
        Node right;
        Node(int val) {
            this.val = val;
            left = null;
            right = null;
        }
    }
    public static Node constructTree(int[] arr, int n) {
        if (n == 0) return null;
        Node root = new Node(arr[0]);
        Queue<Node> queue = new LinkedList<>();
        queue.add(root);
        int i = 1;
        while (i < n) {
            Node currentNode = queue.poll();
            if (arr[i] != -1) {
                currentNode.left = new Node(arr[i]);
                queue.add(currentNode.left);
            }
            i++;
            if (i < n && arr[i] != -1) {
                currentNode.right = new Node(arr[i]);
                queue.add(currentNode.right);
            }
            i++;
        }
        return root;
    }
    public static int minTimeToBurnTree(Node root, int target) {
        if (root == null) return 0;
        Queue<Node> queue = new LinkedList<>();
        queue.add(root);
        int time = 0;
        boolean found = false;
        while (!queue.isEmpty()) {
            int size = queue.size();
            for (int i = 0; i < size; i++) {
                Node currentNode = queue.poll();
                if (currentNode.val == target) {
                    found = true;
                }
                if (currentNode.left != null) {
                    queue.add(currentNode.left);
                }
                if (currentNode.right != null) {
                    queue.add(currentNode.right);
                }
            }
            if (found) time++;
        }
        return time;
    }
