from collections import deque

class Node:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

def construct_tree(arr, n):
    if n == 0:
        return None
    root = Node(arr[0])
    queue = deque([root])
    i = 1
    while i < n:
        current_node = queue.popleft()
        if arr[i] != -1:
            current_node.left = Node(arr[i])
            queue.append(current_node.left)
        i += 1
        if i < n and arr[i] != -1:
            current_node.right = Node(arr[i])
            queue.append(current_node.right)
        i += 1
    return root

def min_time_to_burn_tree(root, target):
    if root is None:
        return 0
    queue = deque([root])
    time = 0
    found = False
    while queue:
        size = len(queue)
        for _ in range(size):
            current_node = queue.popleft()
            if current_node.val == target:
                found = True
            if current_node.left:
                queue.append(current_node.left)
            if current_node.right:
                queue.append(current_node.right)
        if found: time += 1
    return time

